INSERT OR IGNORE INTO knowledge_documents (id, tenant_id, source_type, title, content, content_hash, word_count, chunk_count, status, is_active, created_at, updated_at) VALUES ('kb_syndic_001', 'tenant_ZGVtby5tYXplQGNvY2NpbmVsbGUuYWk', 'text', 'Horaires et contact du syndic', 'Le syndic Horizon est joignable du lundi au vendredi. Les horaires sont de neuf heures à midi et de quatorze heures à dix-huit heures. Le bureau est fermé le week-end et les jours fériés. En cas de problème urgent en dehors de ces horaires, un service d''astreinte est disponible pour les urgences techniques graves. Une urgence grave est par exemple une fuite d''eau importante. C''est aussi une panne d''ascenseur avec une personne bloquée. Pour toute demande non urgente, vous pouvez laisser un message. Le syndic vous rappelle sous deux jours ouvrés.', '53d7c71500bb89b729178248aa9e2592328332f5d0dfca9953dc21e63700a1a0', 91, 0, 'indexed', 1, datetime('now'), datetime('now'));
INSERT OR IGNORE INTO knowledge_documents (id, tenant_id, source_type, title, content, content_hash, word_count, chunk_count, status, is_active, created_at, updated_at) VALUES ('kb_syndic_002', 'tenant_ZGVtby5tYXplQGNvY2NpbmVsbGUuYWk', 'text', 'Paiement des charges de copropriété', 'Les charges de copropriété sont appelées chaque trimestre. Vous recevez un appel de fonds avant chaque échéance. Le paiement se fait par prélèvement automatique ou par virement. Le prélèvement automatique est la solution la plus simple. Pour mettre en place le prélèvement, contactez le syndic. Vous pouvez aussi payer par chèque envoyé au bureau du syndic. En cas de difficulté de paiement, contactez le syndic rapidement. Un échéancier peut être étudié au cas par cas. Tout retard de paiement peut entraîner des frais supplémentaires.', 'be01995d8046bbe8a61e7da2a9438821176bbd90c451f5083ae87a6e1dab32d5', 84, 0, 'indexed', 1, datetime('now'), datetime('now'));
INSERT OR IGNORE INTO knowledge_documents (id, tenant_id, source_type, title, content, content_hash, word_count, chunk_count, status, is_active, created_at, updated_at) VALUES ('kb_syndic_003', 'tenant_ZGVtby5tYXplQGNvY2NpbmVsbGUuYWk', 'text', 'Comprendre le montant des charges', 'Les charges couvrent les dépenses communes de l''immeuble. Elles comprennent l''entretien des parties communes. Elles comprennent aussi l''eau froide des parties communes. Elles incluent l''électricité des couloirs et de l''éclairage. Elles incluent l''entretien de l''ascenseur quand il y en a un. Elles incluent le contrat du gardien quand il y en a un. Elles incluent l''assurance de l''immeuble. Le montant peut varier d''une année sur l''autre. Une augmentation s''explique souvent par un contrat révisé. Elle peut venir de travaux votés en assemblée générale. Le détail figure dans le décompte annuel de charges. Vous pouvez demander ce décompte au syndic à tout moment.', 'c0b94482600d571b473319dd6950c08da9b35ab72101a3b33c41a7123daf7e89', 102, 0, 'indexed', 1, datetime('now'), datetime('now'));
INSERT OR IGNORE INTO knowledge_documents (id, tenant_id, source_type, title, content, content_hash, word_count, chunk_count, status, is_active, created_at, updated_at) VALUES ('kb_syndic_004', 'tenant_ZGVtby5tYXplQGNvY2NpbmVsbGUuYWk', 'text', 'Entretien de l''ascenseur', 'L''ascenseur fait l''objet d''un contrat d''entretien régulier. Une société spécialisée intervient pour la maintenance. Une visite de contrôle a lieu plusieurs fois par an. En cas de panne, signalez-la immédiatement au syndic. Si une personne est bloquée dans la cabine, c''est une urgence. Dans ce cas, le service d''astreinte intervient en priorité. Le coût de l''entretien est réparti dans les charges communes. Les travaux importants sur l''ascenseur sont votés en assemblée.', 'df9eae9a9cee315a9e48bb98706eb491ea7405de4f79d0bff7309e1436de85e1', 71, 0, 'indexed', 1, datetime('now'), datetime('now'));
INSERT OR IGNORE INTO knowledge_documents (id, tenant_id, source_type, title, content, content_hash, word_count, chunk_count, status, is_active, created_at, updated_at) VALUES ('kb_syndic_005', 'tenant_ZGVtby5tYXplQGNvY2NpbmVsbGUuYWk', 'text', 'Signaler une fuite d''eau ou un dégât des eaux', 'Une fuite d''eau doit être signalée au syndic sans attendre. Si la fuite est importante, c''est une urgence technique. Coupez l''arrivée d''eau si vous pouvez le faire sans danger. Le syndic mandate un plombier pour constater l''origine de la fuite. Si la fuite vient d''un autre logement, le syndic fait le lien. Pensez à prévenir aussi votre assurance habitation. Pour un dégât des eaux entre voisins, un constat amiable est utile. Le syndic vous accompagne dans les démarches avec l''assurance. Conservez les photos des dégâts pour votre dossier.', '51991f1416ee8ed829e7cacecdc811e806c22f54cbbc64a067acf83e12b27bbb', 88, 0, 'indexed', 1, datetime('now'), datetime('now'));
INSERT OR IGNORE INTO knowledge_documents (id, tenant_id, source_type, title, content, content_hash, word_count, chunk_count, status, is_active, created_at, updated_at) VALUES ('kb_syndic_006', 'tenant_ZGVtby5tYXplQGNvY2NpbmVsbGUuYWk', 'text', 'Travaux dans les parties communes', 'Les travaux dans les parties communes sont décidés collectivement. Ils sont votés lors de l''assemblée générale des copropriétaires. Chaque copropriétaire reçoit une convocation avant l''assemblée. L''ordre du jour précise les travaux proposés au vote. Un devis est présenté pour chaque projet de travaux. Une fois votés, les travaux sont planifiés par le syndic. Le financement passe par un appel de fonds spécifique. Les copropriétaires sont informés du calendrier des travaux. Pour une question sur des travaux en cours, contactez le syndic.', '258a8fe35de21347a3d5c16cc31e615b678d7802f0468c301bfb9c5d19c6453e', 81, 0, 'indexed', 1, datetime('now'), datetime('now'));
INSERT OR IGNORE INTO knowledge_documents (id, tenant_id, source_type, title, content, content_hash, word_count, chunk_count, status, is_active, created_at, updated_at) VALUES ('kb_syndic_007', 'tenant_ZGVtby5tYXplQGNvY2NpbmVsbGUuYWk', 'text', 'Assemblée générale des copropriétaires', 'L''assemblée générale réunit tous les copropriétaires une fois par an. Elle peut aussi être convoquée en réunion exceptionnelle si besoin. Vous recevez une convocation au moins vingt et un jours avant. La convocation précise la date, le lieu et l''ordre du jour. Si vous ne pouvez pas venir, vous pouvez donner un pouvoir. Le pouvoir permet à une personne de voter à votre place. Les décisions sont prises par un vote des copropriétaires présents. Un compte rendu est envoyé après l''assemblée. Ce compte rendu reprend toutes les décisions votées.', 'c86ab4d9abb6b2fe9fb939dfc66bec6ebba9c86cf367f472afddb56fcd0c802c', 89, 0, 'indexed', 1, datetime('now'), datetime('now'));
INSERT OR IGNORE INTO knowledge_documents (id, tenant_id, source_type, title, content, content_hash, word_count, chunk_count, status, is_active, created_at, updated_at) VALUES ('kb_syndic_008', 'tenant_ZGVtby5tYXplQGNvY2NpbmVsbGUuYWk', 'text', 'Rôle du gardien de l''immeuble', 'Le gardien assure l''entretien courant des parties communes. Il sort les conteneurs de déchets selon le calendrier de collecte. Il surveille le bon état général de l''immeuble. Il peut réceptionner certains prestataires pour le syndic. Le gardien n''est pas habilité à régler les litiges entre voisins. Pour un litige, c''est le syndic qu''il faut contacter. Les horaires de présence du gardien sont affichés dans le hall. Pour une question sur la propreté, vous pouvez voir le gardien.', 'f8ad66cb7e7e3fb2d8e212cfb9df50cbb8d1ff3714f5c30dcfd1fe9e89ed4e7c', 77, 0, 'indexed', 1, datetime('now'), datetime('now'));
INSERT OR IGNORE INTO knowledge_documents (id, tenant_id, source_type, title, content, content_hash, word_count, chunk_count, status, is_active, created_at, updated_at) VALUES ('kb_syndic_009', 'tenant_ZGVtby5tYXplQGNvY2NpbmVsbGUuYWk', 'text', 'Litiges et nuisances entre voisins', 'Le syndic gère les parties communes de l''immeuble. Un conflit privé entre voisins relève d''abord d''un dialogue direct. Pour des nuisances sonores répétées, parlez-en au voisin concerné. Si le problème persiste, vous pouvez en informer le syndic. Le syndic peut rappeler le règlement de copropriété à tous. Le règlement de copropriété fixe les règles de vie commune. En cas de trouble grave, des démarches officielles sont possibles. Le syndic peut vous orienter vers la bonne procédure.', 'd5906fa98ba2d972baf244a32457528c0469ba02b68b2c7f64edf9b366c1660a', 76, 0, 'indexed', 1, datetime('now'), datetime('now'));
INSERT OR IGNORE INTO knowledge_documents (id, tenant_id, source_type, title, content, content_hash, word_count, chunk_count, status, is_active, created_at, updated_at) VALUES ('kb_syndic_010', 'tenant_ZGVtby5tYXplQGNvY2NpbmVsbGUuYWk', 'text', 'Vendre ou louer son logement dans la copropriété', 'En cas de vente, le syndic fournit des documents au notaire. Ces documents informent l''acheteur sur la copropriété. Ils indiquent les charges et l''état des comptes du vendeur. Prévenez le syndic dès que la vente est engagée. En cas de location, vous restez le copropriétaire responsable. C''est vous qui recevez les appels de charges. Pensez à communiquer au syndic vos coordonnées à jour. Une adresse à jour évite tout retard dans les échanges.', 'baa360f8b6ea3aa9f5d85b268e66dee818747078323ddd226f4130fb1b0bda79', 73, 0, 'indexed', 1, datetime('now'), datetime('now'));
INSERT OR IGNORE INTO knowledge_documents (id, tenant_id, source_type, title, content, content_hash, word_count, chunk_count, status, is_active, created_at, updated_at) VALUES ('kb_syndic_011', 'tenant_ZGVtby5tYXplQGNvY2NpbmVsbGUuYWk', 'text', 'Demander un rendez-vous avec le syndic', 'Vous pouvez demander un rendez-vous avec le syndic. Le rendez-vous permet d''examiner votre situation en détail. Précisez le motif de votre demande lors de la prise de rendez-vous. Un motif clair permet de préparer le rendez-vous à l''avance. Les rendez-vous se tiennent pendant les horaires d''ouverture. Vous recevez une confirmation après la prise de rendez-vous. Si vous avez un empêchement, prévenez le syndic à l''avance. Cela permet de proposer le créneau à une autre personne.', '7ec5683c065cdf423298747cb14c8026ef155b8922e7444eb676e011a4dd6f74', 75, 0, 'indexed', 1, datetime('now'), datetime('now'));
